class Solution(object):
    def countSubstrings(self, s, t):
        result = 0
        s_set = set()
        for i in range(len(s)):
            for j in range(i, len(s)):
                sub = s[i:j+1]
                for k in range(len(t) - len(sub) + 1):
                    t_sub = t[k:k+len(sub)]
                    diff = sum(1 for a, b in zip(sub, t_sub) if a != b)
                    if diff == 1:
                        result += 1
        return result
